import{_ as t,c as a,o as s,a5 as r}from"./chunks/framework.CgT1UzWm.js";const g=JSON.parse('{"title":"FastAPI — PostgreSQL REST API Benchmark, July 2026","titleTemplate":"NpgsqlRest","description":"FastAPI 0.139.0 in the July 2026 PostgreSQL REST API benchmark: from bottom tier to winning the flagship scenario at every concurrent load level — because of one deployment flag.","frontmatter":{"layout":"doc","outline":[2,3],"title":"FastAPI — PostgreSQL REST API Benchmark, July 2026","titleTemplate":"NpgsqlRest","description":"FastAPI 0.139.0 in the July 2026 PostgreSQL REST API benchmark: from bottom tier to winning the flagship scenario at every concurrent load level — because of one deployment flag.","head":[["link",{"rel":"canonical","href":"https://npgsqlrest.github.io/blog/benchmarks-2026-07/fastapi.html"}],["meta",{"property":"og:url","content":"https://npgsqlrest.github.io/blog/benchmarks-2026-07/fastapi.html"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:title","content":"FastAPI — PostgreSQL REST API Benchmark, July 2026"}],["meta",{"property":"og:description","content":"FastAPI 0.139.0 in the July 2026 PostgreSQL REST API benchmark: from bottom tier to winning the flagship scenario at every concurrent load level — because of one deployment flag."}],["meta",{"property":"og:image","content":"https://npgsqlrest.github.io/og-image.png"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"FastAPI — PostgreSQL REST API Benchmark, July 2026"}],["meta",{"name":"twitter:description","content":"FastAPI 0.139.0 in the July 2026 PostgreSQL REST API benchmark: from bottom tier to winning the flagship scenario at every concurrent load level — because of one deployment flag."}],["meta",{"name":"twitter:image","content":"https://npgsqlrest.github.io/og-image.png"}]]},"headers":[],"relativePath":"blog/benchmarks-2026-07/fastapi.md","filePath":"blog/benchmarks-2026-07/fastapi.md","lastUpdated":1782480183000}'),n={name:"blog/benchmarks-2026-07/fastapi.md"};function i(o,e,l,h,p,c){return s(),a("div",null,e[0]||(e[0]=[r(`<h1 id="fastapi-0-139-0-uvicorn-asyncpg" tabindex="-1">FastAPI 0.139.0 (uvicorn + asyncpg) <a class="header-anchor" href="#fastapi-0-139-0-uvicorn-asyncpg" aria-label="Permalink to &quot;FastAPI 0.139.0 (uvicorn + asyncpg)&quot;">​</a></h1><p class="blog-meta"><span class="tag">Benchmark</span> · <span class="tag">Python</span> · <span class="tag">July 2026</span></p><p>Part of the <a href="/blog/benchmarks-2026-07/">PostgreSQL REST API Benchmark, July 2026</a> series.</p><h2 id="at-a-glance" tabindex="-1">At a glance <a class="header-anchor" href="#at-a-glance" aria-label="Permalink to &quot;At a glance&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td><strong>Version</strong></td><td>FastAPI 0.139.0 on Python 3.14, uvicorn 0.51 with uvloop + httptools, orjson responses</td></tr><tr><td><strong>PostgreSQL driver</strong></td><td>asyncpg 0.31.0 — per-worker pool, workers × 12 ≈ 100 aggregate connections</td></tr><tr><td><strong>Concurrency model</strong></td><td>Async event loop, one uvicorn worker per core (<code>--workers $(nproc)</code>)</td></tr><tr><td><strong>Lines of code</strong></td><td>123</td></tr><tr><td><strong>Podiums</strong></td><td>🥇 4 · 🥈 3 · 🥉 16 — of 38 combinations</td></tr><tr><td><strong>Source</strong></td><td><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/fastapi-app-v0.139.0" target="_blank" rel="noreferrer">fastapi-app-v0.139.0</a></td></tr></tbody></table></div></div><p><strong>The verdict in one sentence: the biggest ranking move of the round belongs to FastAPI — from bottom tier in January to winning the flagship scenario at every concurrent load level — and the cause was a deployment flag, not the framework.</strong></p><h2 id="implementation" tabindex="-1">Implementation <a class="header-anchor" href="#implementation" aria-label="Permalink to &quot;Implementation&quot;">​</a></h2><p>Standard async FastAPI (<a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/fastapi-app-v0.139.0/app.py" target="_blank" rel="noreferrer">app.py</a>): typed <code>Query(...)</code> parameters, an asyncpg pool per worker, <code>ORJSONResponse</code> as the default serializer. The line that decided this round&#39;s story is in the Dockerfile:</p><details class="code-collapsible" open><summary>dockerfile</summary><div class="language-dockerfile vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">dockerfile</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;"># Workers = CPU cores so the single-threaded event loop can use the whole machine,</span></span>
<span class="line"><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;"># matching natively multi-threaded runtimes (Go, Rust, .NET, JVM).</span></span>
<span class="line"><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;">CMD</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> uvicorn app:app --workers \${WORKERS:-$(nproc)} --loop uvloop --http httptools \\</span></span>
<span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">    --no-access-log --log-level warning</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></details><details class="code-collapsible" open><summary>python</summary><div class="language-python vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes catppuccin-latte catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">pool </span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">=</span><span style="--shiki-light:#8839EF;--shiki-dark:#CBA6F7;"> await</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;"> asyncpg</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">.</span><span style="--shiki-light:#1E66F5;--shiki-dark:#89B4FA;">create_pool</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">(</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">...</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span><span style="--shiki-light:#E64553;--shiki-light-font-style:italic;--shiki-dark:#EBA0AC;--shiki-dark-font-style:italic;"> min_size</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">=</span><span style="--shiki-light:#FE640B;--shiki-dark:#FAB387;">2</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">,</span><span style="--shiki-light:#E64553;--shiki-light-font-style:italic;--shiki-dark:#EBA0AC;--shiki-dark-font-style:italic;"> max_size</span><span style="--shiki-light:#179299;--shiki-dark:#94E2D5;">=</span><span style="--shiki-light:#4C4F69;--shiki-dark:#CDD6F4;">POOL_MAX_SIZE</span><span style="--shiki-light:#7C7F93;--shiki-dark:#9399B2;">)</span><span style="--shiki-light:#9CA0B0;--shiki-light-font-style:italic;--shiki-dark:#6C7086;--shiki-dark-font-style:italic;">  # 12 per worker</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><p>In January this service ran <strong>one uvicorn worker</strong> on an 8-core machine. Everything else about the application is ordinary FastAPI.</p><h2 id="results" tabindex="-1">Results <a class="header-anchor" href="#results" aria-label="Permalink to &quot;Results&quot;">​</a></h2><h3 id="the-headline-perf-test" tabindex="-1">The headline: perf-test <a class="header-anchor" href="#the-headline-perf-test" aria-label="Permalink to &quot;The headline: perf-test&quot;">​</a></h3><p>FastAPI won the comprehensive 23-datatype serialization scenario at <strong>every concurrent load level</strong>, by the largest margins of any category winner in the round:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>perf-test, 1 record</th><th style="text-align:right;">1 VU</th><th style="text-align:right;">50 VU</th><th style="text-align:right;">100 VU</th><th style="text-align:right;">200 VU</th></tr></thead><tbody><tr><td>req/s</td><td style="text-align:right;">854 (#2)</td><td style="text-align:right;">🥇 5,048</td><td style="text-align:right;">🥇 5,109</td><td style="text-align:right;">🥇 5,053</td></tr></tbody></table></div></div><p>That is 45% ahead of the #2 at 100 VU (NpgsqlRest SQL-files AOT, 3,524) and 73% ahead of Go (2,948, #6). Its scaling factor — 854 → 5,109 from 1 to 100 VU, a <strong>6.0×</strong> multiplier — is the best in the field: eight independent event loops, each with its own connection pool, and almost no shared state to contend on.</p><p>On heavier rows it stays on the podium at every concurrency: #3 behind Swoole and Go at 10, 100, and 500 records (1,576 / 182 / 39 req/s at 50 VU). Large payloads were quietly excellent too — 342 req/s at 50 VU/500 KB (#1, its fourth gold), 1,402 at 50 VU/100 KB (#2) — and nested JSON was #3 across all six combinations.</p><h3 id="where-the-bill-arrives" tabindex="-1">Where the bill arrives <a class="header-anchor" href="#where-the-bill-arrives" aria-label="Permalink to &quot;Where the bill arrives&quot;">​</a></h3><p>Python&#39;s per-request costs did not disappear; they moved:</p><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th>Scenario</th><th>Result</th></tr></thead><tbody><tr><td>Many parameters</td><td>5,996 req/s at 50 VU (#18) — validating 20 typed query params through <code>Query(...)</code> is expensive; only PostgREST and Django are slower</td></tr><tr><td>Minimal baseline</td><td>11,610 req/s at 100 VU (#17) — mid-to-lower table when there is no payload to win on</td></tr><tr><td>perf-test at 1 VU, heavy rows</td><td>270 (#18) at 10 rec, 64 (#19) at 100 rec, 12 (#20) at 500 rec — single-request row materialization is the slowest in the field; concurrency across workers is what hides it</td></tr></tbody></table></div></div><p>The 1 VU column deserves emphasis: FastAPI is simultaneously #2 at 1 record and #20 at 500 records. Per-row <code>dict(row)</code> conversion in Python is slow; eight parallel workers mask it completely at 50+ VU, where the same workload ranks #3.</p><h3 id="latency" tabindex="-1">Latency <a class="header-anchor" href="#latency" aria-label="Permalink to &quot;Latency&quot;">​</a></h3><p>At its winning combinations FastAPI also posted the field&#39;s best tails: p99 of <strong>25 ms</strong> at 50 VU/1 rec and <strong>54 ms</strong> at 100 VU/1 rec — the lowest of all 20 services on both, roughly half of Go&#39;s 48/97 ms. At 1 VU it matches the leaders at 2 ms. The params weakness shows in latency too: 126 ms p99 at 200 VU, versus 40–50 ms for the top tier.</p><h2 id="resource-usage" tabindex="-1">Resource usage <a class="header-anchor" href="#resource-usage" aria-label="Permalink to &quot;Resource usage&quot;">​</a></h2><div class="table-container"><div class="table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:right;">Peak memory</th><th style="text-align:right;">Avg memory</th><th style="text-align:right;">Avg CPU</th></tr></thead><tbody><tr><td style="text-align:right;">282 MB</td><td style="text-align:right;">237 MB</td><td style="text-align:right;"><strong>200.4%</strong></td></tr></tbody></table></div></div><p>Throughput is bought with hardware: alongside Django (229.6%), FastAPI posted the highest CPU usage in the field — two of four pinned cores busy on average, roughly double Go&#39;s 90% for comparable flagship-scenario numbers. Memory is moderate for an 8-process Python deployment: 282 MB peak, well under the Node cluster services, but ten times Swoole&#39;s average.</p><h2 id="analysis" tabindex="-1">Analysis <a class="header-anchor" href="#analysis" aria-label="Permalink to &quot;Analysis&quot;">​</a></h2><p>The single most transferable lesson of this benchmark round is on this page: <strong>deployment configuration can matter more than framework choice.</strong> The framework did not get 6× faster between January and July — its process count did. A single-worker uvicorn deployment on multi-core hardware silently forfeits most of the machine, and January&#39;s &quot;FastAPI is slow&quot; ranking was measuring that forfeit, not the framework. If you run FastAPI in production, <code>--workers</code>, uvloop, and a per-worker asyncpg pool are not optimizations; they are the baseline.</p><p>The honest counterweight: FastAPI now occupies the podium by spending more CPU than anyone except Django, its 16 bronzes are mostly third places behind Swoole and Go, and scenarios dominated by parsing (params) or bare routing (minimal) still rank it in the bottom quartile. Python&#39;s per-request cost is real — this round shows it can be parallelized away exactly where payload work dominates, and nowhere else.</p><p><strong>January → July movement:</strong> bottom tier → #1 in the comprehensive perf-test at every concurrent load level, taking the crown NpgsqlRest held in January; params and minimal stayed low-table. Rankings only — the methodology changed too much for absolute comparisons.</p><h2 id="explore-on-github" tabindex="-1">Explore on GitHub <a class="header-anchor" href="#explore-on-github" aria-label="Permalink to &quot;Explore on GitHub&quot;">​</a></h2><p>Everything this page claims can be checked against the running code and the raw output:</p><ul><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/fastapi-app-v0.139.0" target="_blank" rel="noreferrer">Application source</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/_postgres/init.sql" target="_blank" rel="noreferrer">The PostgreSQL functions every service calls</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/_k6/scripts" target="_blank" rel="noreferrer">k6 load scripts</a></li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/tree/202607131327/src/_k6/results/202607131327" target="_blank" rel="noreferrer">This run&#39;s per-test k6 summaries</a> — filter by this service&#39;s name</li><li><a href="https://github.com/NpgsqlRest/pg_function_load_tests/blob/202607131327/src/_k6/results/202607131327/results.csv" target="_blank" rel="noreferrer">Complete dataset: results.csv</a></li></ul><hr><p><strong>Series:</strong> <a href="/blog/benchmarks-2026-07/">Introduction</a> · <a href="/blog/benchmarks-2026-07/analysis.html">Overall Analysis</a> · <a href="/blog/benchmarks-2026-07/results.html">Raw Results</a></p><p><strong>Next framework:</strong> <a href="/blog/benchmarks-2026-07/django.html">Django →</a></p>`,36)]))}const m=t(n,[["render",i]]);export{g as __pageData,m as default};
